void compute_hmac_evp(const unsigned char *key, size_t key_len, 
                      const unsigned char *message, size_t message_len,
                      unsigned char *hmac_result, size_t *result_len) {

    EVP_MAC_CTX *mdctx = NULL;
    int ret = 0;

    // 1. Create an EVP_MAC context
    mdctx = EVP_MAC_CTX_new();
    if (!mdctx) {
        ERR_print_errors_fp(stderr);
        return;
    }

    // 2. Initialize with key and digest via OSSL_PARAM
    // We use OSSL_PARAM to specify the key and the digest algorithm (SHA256)
    // Note: The exact usage of OSSL_PARAM for HMAC setup often involves specific helper functions or iterating parameters.
    // For EVP_MAC, the setup is typically done by specifying the type and value for the key and algorithm.

    // Setup Parameters for HMAC-SHA256
    OSSL_PARAM params[2];

    // Parameter 1: Key
    params[0].name = N_PARAM_KEY;
    params[0].value = key;
    params[0].length = key_len;

    // Parameter 2: Digest Algorithm (SHA256)
    params[1].name = N_PARAM_DIGEST;
    params[1].value = EVP_sha256(); // Use the EVP_algorithm function to get the digest identifier
    params[1].length = 0; // Length is typically 0 for algorithm selection

    if (EVP_MAC_CTX_init(mdctx, &params, 2) != 1) {
        fprintf(stderr, "EVP_MAC_CTX_init failed.\n");
        EVP_MAC_CTX_free(mdctx);
        return;
    }

    // 3. Update (Provide the message data)
    // In EVP_MAC, the update operation usually feeds the data.
    if (EVP_MAC_update(mdctx, message, message_len) != 1) {
        fprintf(stderr, "EVP_MAC_update failed.\n");
        EVP_MAC_CTX_free(mdctx);
        return;
    }

    // 4. Finalize (Compute the MAC)
    if (EVP_MAC_final(mdctx, hmac_result, result_len) != 1) {
        fprintf(stderr, "EVP_MAC_final failed.\n");
        EVP_MAC_CTX_free(mdctx);
        return;
    }

    printf("HMAC-SHA256 computed successfully.\n");
}

